UPDATE FOODM f
SET f.foodMaterialCountAll = f.foodMaterialCountAll - (
    SELECT SUM(u.usedCount) * #{saleCount}
    FROM USED u
    WHERE u.foodMaterial_Id = f.foodMaterial_Id
      AND u.menu_Id = #{menuId}
)
WHERE f.bId = #{bId}
  AND EXISTS (
    SELECT 1 FROM USED u
    WHERE u.foodMaterial_Id = f.foodMaterial_Id
      AND u.menu_Id = #{menuId}
)
  AND NOT EXISTS (
    SELECT 1
    FROM FOODM f2
             JOIN (
        SELECT foodMaterial_Id, SUM(usedCount) * #{saleCount} AS needCount
        FROM USED
        WHERE menu_Id = #{menuId}
        GROUP BY foodMaterial_Id
    ) need ON f2.foodMaterial_Id = need.foodMaterial_Id
    WHERE f2.bId = #{bId}
      AND f2.foodMaterialCountAll < need.needCount
)

